protected String[] flatten(Options options, String[] arguments, boolean stopAtNonOption)
{
    List<String> tokens = new ArrayList<>();

    boolean eatTheRest = false;

    for (int i = 0; i < arguments.length; i++)
    {
        String arg = arguments[i];

        if ("--".equals(arg))
        {
            eatTheRest = true;
            tokens.add("--");
        }
        else if ("-".equals(arg))
        {
            tokens.add("-");
        }
        else if (arg.startsWith("-"))
        {
            String opt = Util.stripLeadingHyphens(arg);
            String[] splitArg = arg.split("=", 2);
            String optionKey = splitArg[0];
            String optionValue = splitArg.length > 1 ? splitArg[1] : null;

            if (optionValue != null && options.hasOption(optionKey))
            {
                tokens.add(optionKey);
                tokens.add(optionValue);
            }
            else if (options.hasOption(opt))
            {
                tokens.add(arg);
            }
            else if (optionKey.length() == 2 && options.hasOption(optionKey))
            {
                // the format is --foo=value or -foo=value
                // the format is a special properties option (-Dproperty=value)
                tokens.add(optionKey);
                if (optionValue != null)
                {
                    tokens.add(optionValue);
                }
            }
            else
            {
                eatTheRest = stopAtNonOption;
                tokens.add(arg);
            }
        }
        else
        {
            tokens.add(arg);
        }

        if (eatTheRest)
        {
            for (i++; i < arguments.length; i++)
